var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"STUDENT_EXTRA_A_TWINTAIL","text":{"KOREA":"그 많은 녀석들을 혼자 때려눕히다니…!","JPN":"あの大勢のやつらを一人で倒すなんて……！","ENG":"She knocked out all those thugs by herself...!","TWN":"她一個人就把那些人都打趴咧…！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STUDENT_EXTRA_B_TWINTAIL","text":{"KOREA":"엄청나. 역시 아카데미에서 인정 받은 엘리트 카운터다워.","JPN":"すごい。さすがアカデミーから認められたカウンターだな。","ENG":"Amazing. No wonder the Academy recognizes her as an elite.","TWN":"好強，不愧是受到學院認可的菁英制裁者。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"쳇, 애송이 녀석들과 비슷한 급인 줄 알았는데 착오였군.","JPN":"チッ、二人組のガキと似たようなランクだと思ったが､勘違いだったか。","ENG":"Tch, I guess I was wrong to assume you were on the same level as those idiots.","TWN":"嘖，我還以為你的實力和那二個小鬼差不多，是我誤會了。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"이제야 너희와 나의 격차를 알겠어? 알았으면 지금이라도 무릎 꿇고 빌어보라구.","JPN":"やっと私との実力の差に気付いた？　わかったなら、今からでも跪いて詫びてみなさいよ。","ENG":"Now you see the difference? It's not too late for you to kneel and beg for forgiveness.","TWN":"現在知道我和你們是不同層次的吧？那還不趕快跪下求饒！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"<color=#ffd34c>감히 아카데미 학생을 얕보고 덤벼서 죄송합니다</color>, 라고 말이야.","JPN":"<color=#ffd34c>アカデミーの生徒をなめて飛びかかって申し訳ありませんでした</color>、ってね。","ENG":"Say, <color=#ffd34c>\\"I'm sorry for underestimating an Academy student and attacking them.\\"</color>","TWN":"快點道歉說，<color=#ffd34c>對不起，我有眼不識泰山，竟敢招惹學院的學生</color>。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"…그래.","JPN":"……ああ。","ENG":"...Sure.","TWN":"…好吧。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"우리가 졌다. 칼솜씨가 제법이군. 얕본 건 사과하지.","JPN":"俺らの負けだ。素晴らしい剣の腕前だな。なめたことは謝る。","ENG":"We admit defeat. Your skills are incredible. I apologize for misjudging you.","TWN":"是我們技不如人，你的刀法確實有兩下子，對不起，是我太小看你。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"흥, 장난해? 사과를 하고 싶은 거라면 그 꼿꼿한 허리부터 제대로 숙이라고.","JPN":"ふん、ふざけないでよ。謝るつもりなら、その腰をしっかり90度にかがめたら？","ENG":"Hmph, are you serious? If you're gonna apologize, do it properly and bow 90 degrees!","TWN":"哼，這算什麼道歉？道歉時要彎腰不是基本的嗎？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"그런데 말이야…","JPN":"ところでさ……","ENG":"But I wonder...","TWN":"不過…"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"네 칼이 아무리 빨라도… 총알보다 빠를까…?","JPN":"いくらお前の剣が速くても……銃弾より速いかな……？","ENG":"If your sword... is faster than a bullet...?","TWN":"你的刀再怎麼快…快得過子彈嗎…？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"…뭐?","JPN":"……は？","ENG":"...What?","TWN":"…蛤？"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"뭐라고 중얼거리는 거야? 잘 안 들리잖…","JPN":"何ぶつぶつ言っててるの？　よく聞こえな……","ENG":"What are you muttering? I can't hear you–","TWN":"你說什麼？我聽不清楚…"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAIEL_SCHOOL_NPC_NULL","text":{"KOREA":"으헥?!","JPN":"グホッ！？","ENG":"Eck?!","TWN":"哇啊？！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"큭큭, 방심했군. 이 한 발을 위해 다가오길 기다렸지.","JPN":"ククッ、油断したな。この一発のために近づくのを待ってたんだ。","ENG":"Keke... You let your guard down. I was waiting for you to get closer to me.","TWN":"呵呵，你太大意了，為了射出這一發子彈，我一直在等你靠近呢。"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"이걸로 한 놈은 처리…","JPN":"これで一人は片付け……","ENG":"That's one down, now...","TWN":"這樣就處理掉一個…"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"SELLER_NPC_ACADEMY_MARKET","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SELLER_NPC_ACADEMY_MARKET","text":{"KOREA":"음?!","JPN":"むっ！？","ENG":"Huh?","TWN":"嗯？！"},"stage":{"bg":"NEWTOWN_NIGHT","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"NAIEL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};